import {
  combineHeaders,
  createJsonResponseHandler,
  lazySchema,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtConfig } from './pixelart-config';
import { pixelArtFailedResponseHandler } from './pixelart-error';

export type PixelArtImageModelId =
  | 'pixelart-v1'
  | 'pixelart-v2'
  | 'pixelart-hd'
  | (string & {});

export type PixelArtImageSettings = {
  /**
   * The output image size (e.g. "512x512", "1024x1024").
   */
  size?: string;

  /**
   * The pixel art style to apply.
   * - "pixel": Classic pixel art look
   * - "retro": Retro arcade style
   * - "8bit": 8-bit era aesthetic
   */
  style?: 'pixel' | 'retro' | '8bit';

  /**
   * The pixel density for the generated image.
   * Higher values produce finer pixel grids.
   */
  pixelDensity?: number;
};

// Minimal response schema — only includes properties needed for the implementation.
// Kept lean to limit breakage when the API changes.
const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      created: z.number().nullish(),
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 1;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly settings: PixelArtImageSettings,
    private readonly config: PixelArtConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (seed != null) {
      warnings.push({ type: 'unsupported', feature: 'seed' });
    }

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'PixelArt does not support aspect ratio. Use `size` instead.',
      });
    }

    // Provider-specific options passed at call time take precedence over
    // constructor-level settings, which in turn fall back to the standard
    // `size` parameter from the core SDK.
    const pixelartOptions =
      ((providerOptions.pixelart ?? {}) as PixelArtImageSettings);

    const resolvedSize =
      pixelartOptions.size ?? this.settings.size ?? size ?? undefined;
    const resolvedStyle =
      pixelartOptions.style ?? this.settings.style ?? undefined;
    const resolvedPixelDensity =
      pixelartOptions.pixelDensity ?? this.settings.pixelDensity ?? undefined;

    const { value: response, responseHeaders } = await postJsonToApi({
      url: this.config.url({
        path: '/images/generate',
        modelId: this.modelId,
      }),
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        ...(resolvedSize != null ? { size: resolvedSize } : {}),
        ...(resolvedStyle != null ? { style: resolvedStyle } : {}),
        ...(resolvedPixelDensity != null
          ? { pixel_density: resolvedPixelDensity }
          : {}),
      },
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: new Date(),
        modelId: this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

